#include<bits/stdc++.h>
using namespace std;
int p[100010],t[100010];
long long ans[100010];
int main()
{
    int n,x,y;
    scanf("%d%d%d",&n,&x,&y);
    for(int i=1;i<n;i++)
    {
        scanf("%d%d",&p[i],&t[i]);
    }
    for(int i=0;i<840;i++)
    {
        ans[i]=i+x;
        for(int j=1;j<n;j++)
        {
            ans[i]=(ans[i]+p[j]-1)/p[j]*p[j]+t[j];
        }
        ans[i]+=y;
    }
    int q;
    scanf("%d",&q);
    while(q--)
    {
        int x;
        scanf("%d",&x);
        printf("%lld\n",ans[x%840]+x/840*840);
    }
    return 0;
}
